import { colors, fonts } from "../../styles/theme";

// ─── MEDITATION ILLUSTRATION ──────────────────────────────────────────────────
export const MeditationSVG = ({ size = 180 }) => (
  <svg width={size} height={size} viewBox="0 0 200 200" fill="none" aria-hidden="true">
    <ellipse cx="100" cy="100" rx="100" ry="100" fill="#F5EFE8" />
    <circle cx="100" cy="70" r="32" fill="#F0D8B0" opacity="0.8" />
    <polygon points="0,160 60,80 120,160"  fill="#C4A882" />
    <polygon points="60,160 120,85 180,160" fill="#B8976A" />
    <polygon points="120,160 170,100 200,160" fill="#C4A882" />
    <rect x="0" y="160" width="200" height="40" fill="#B8916A" />
    <ellipse cx="100" cy="148" rx="22" ry="10" fill="#9B7A6A" opacity="0.4" />
    <ellipse cx="82"  cy="153" rx="16" ry="7"  fill="#4A3728" transform="rotate(-8,82,153)" />
    <ellipse cx="118" cy="153" rx="16" ry="7"  fill="#4A3728" transform="rotate(8,118,153)" />
    <ellipse cx="100" cy="132" rx="16" ry="20" fill="#9B8EC4" />
    <ellipse cx="78"  cy="140" rx="12" ry="5"  fill="#9B8EC4" transform="rotate(20,78,140)" />
    <ellipse cx="122" cy="140" rx="12" ry="5"  fill="#9B8EC4" transform="rotate(-20,122,140)" />
    <circle cx="70"  cy="147" r="5" fill="#E8C8A8" />
    <circle cx="130" cy="147" r="5" fill="#E8C8A8" />
    <rect   x="96" y="110" width="8" height="10" fill="#E8C8A8" rx="3" />
    <circle cx="100" cy="105" r="14" fill="#E8C8A8" />
    <ellipse cx="100" cy="92" rx="8" ry="6" fill="#4A3728" />
    <circle  cx="100" cy="87" r="5"          fill="#4A3728" />
    <path d="M97 111 Q100 113 103 111" stroke="#C8A888" strokeWidth="1.2" fill="none" strokeLinecap="round" />
  </svg>
);

// ─── LOGO ─────────────────────────────────────────────────────────────────────
export const Logo = ({ size = "md", dark = false }) => {
  const sz = size === "sm" ? 28 : 36;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
      <div style={{
        width: sz, height: sz, borderRadius: 10, flexShrink: 0,
        background: `linear-gradient(135deg, ${colors.purple}, ${colors.purpleLight})`,
        display: "flex", alignItems: "center", justifyContent: "center",
        boxShadow: `0 4px 12px ${colors.purple}40`,
      }}>
        <svg width={sz * 0.56} height={sz * 0.56} viewBox="0 0 20 20" fill="none">
          <circle cx="10" cy="6" r="3.5" fill="white" />
          <path d="M5 17 Q5 12 10 12 Q15 12 15 17" fill="white" opacity="0.8" />
          <path d="M2 10 Q5 8 7 11"  stroke="white" strokeWidth="1.5" strokeLinecap="round" />
          <path d="M18 10 Q15 8 13 11" stroke="white" strokeWidth="1.5" strokeLinecap="round" />
        </svg>
      </div>
      <div>
        <div style={{
          fontFamily: fonts.display,
          fontWeight: 700,
          fontSize: size === "sm" ? 14 : 17,
          color: dark ? "#fff" : colors.purple,
          lineHeight: 1.1,
        }}>
          CalmMind
        </div>
        {size !== "sm" && (
          <div style={{
            fontSize: 9,
            color: dark ? "rgba(255,255,255,0.5)" : colors.textMuted,
            fontFamily: fonts.body,
            lineHeight: 1,
          }}>
            Support For Today, Strength For Tomorrow
          </div>
        )}
      </div>
    </div>
  );
};
